INSERT INTO sense_translations (id, sense_id, language_code, meaning, example) VALUES
  ('6c9543b6-1b09-535d-830f-36a1de35b799', '50f09ea8-80c9-5aeb-8abf-4c6dcc4fcd94', 'fa', 'بودن (صفت یا نام را دنبال می‌کند)', 'او خوب است.'),
  ('2d34eb85-fe1a-56e7-956a-7518c9168102', 'f5df9202-64bb-53de-9cbb-514970270d9f', 'fa', 'برابر بودن با، یکی بودن', 'این کتاب از آن کتاب است.'),
  ('d4984f38-cff5-58a0-95f2-d5acbd90fc5e', '12b1b544-6b4e-5ae3-b195-6f542647175f', 'fa', 'داشتن', 'من یک خانه بزرگ دارم.'),
  ('93e6209c-7770-5ee1-bf30-86bcadcd7eef', '65bc975b-df18-5880-b190-2bb08c5f7b5d', 'fa', 'داشتن', 'این کتاب صفحات زیادی دارد.'),
  ('e30be62a-1dcb-5871-8fff-09cd380f9cbc', '743adb23-bd00-52db-8b38-3d4727643300', 'fa', 'نه', 'این کتاب نه خیلی خوب است.'),
  ('3dd74747-dcfb-5662-be7f-c8324d2a4ef2', '1e8570fa-d29c-5ee1-b5ac-fd29a6ceced5', 'fa', 'بسیار، خیلی', 'این فیلم خیلی خوب بود که من آن را دوبار تماشا کردم.'),
  ('329f3094-8674-5c76-810c-f7c63c64276f', '5e5b8796-5ccb-576a-bfe4-cffef836cbe5', 'fa', 'به طوری که، بدین ترتیب', 'باید زود برویم تا به وقت برسیم.'),
  ('852521ef-6943-5061-97bd-47bf532d08f4', '1f100bad-c828-53f0-8ee6-c9a08572dce8', 'fa', 'کنسرو کردن', 'ما گوجه‌فرنگی را در شیشه کنسرو می‌کنیم.'),
  ('110f5efa-f615-51c7-8ee9-5b5140d63a3c', '045d908e-7f1b-512b-a2c5-653ced04fe8c', 'fa', 'اخراج کردن', 'مدیر کارمند را به دلیل تاخیر بیش‌ازحد اخراج کرد.'),
  ('06c719f7-c93e-56fe-9d2f-9b743463fa31', 'faffdcef-71ec-52bd-ba86-4319918a329d', 'fa', 'فرمان دادن، حکم کردن', 'پادشاه فرمان داد که درهای شهر بسته شود.'),
  ('518e9500-0cdf-53f8-b978-de93e66e1482', 'c9857b5a-8fe9-568d-8a31-1b0c9623d847', 'fa', 'تصمیم گرفتن، اختیار کردن', 'او تصمیم گرفت که به دانشگاه برود.'),
  ('00bdf303-2747-5a48-bd7c-7d9f1cad4139', '9c939a37-4075-5a15-9a50-9476734edde5', 'fa', 'فقط', 'من فقط یک فنجان قهوه می‌خواهم.'),
  ('a6d2d583-2022-576a-b9eb-535d28484c0a', 'b8099537-779b-5411-a163-2daec8fc2971', 'fa', 'دقیقاً', 'ساعت دقیقاً ۱۲ بود وقتی او رسید.'),
  ('5f73eb8c-6915-5d38-917f-1ae6b0eb217a', '8a3d6b8c-5549-5080-a08a-2d44c623b7d2', 'fa', 'بیشتر', 'من بیشتر آب می‌خورم تا تشنگی را برطرف کنم.'),
  ('fcc54812-73fc-5ae3-804b-539fc0382961', '12c79556-8547-5194-a0d1-433a056ec520', 'fa', 'بیشتر', 'امسال بیشتر دانش‌آموز در کلاس حاضر شدند.'),
  ('3e4a6db7-0148-5ec5-8cba-a0c041699217', '5d69a005-0b63-593a-a088-8c169bd48be7', 'fa', 'تر', 'این کتاب جالب‌تر از آن کتاب است.'),
  ('8b96f586-283d-5542-8bd0-4c5178fc40aa', '24986c6c-df1a-5c32-ac02-666ff5cee6e8', 'fa', 'بیشتر', 'او بیشتر از من می‌خندد.'),
  ('58b568d8-ec9c-5b2e-9ad0-92b3ab931438', '3b89aaec-3f3b-5102-b8f4-703a9a681047', 'fa', 'انجام دادن', 'من هر روز ورزش می‌کنم.'),
  ('bcf0bbff-4b99-53f0-8a94-c4bc0307abf6', 'dc7b8bb9-f48d-552f-b982-76e5701e1c19', 'fa', 'کار کردن', 'او تکالیف خود را انجام داد.'),
  ('a4e4a57e-2a93-555d-b1f3-fe5884b899de', '8a4a289b-6e15-5995-8f83-c9cb1ba9c14b', 'fa', 'بار', 'این بار که می‌آیی، لطفاً کتاب‌ات را بیاور.'),
  ('48a606cc-4d68-581d-b67c-1e25f520eddb', '85b197ae-82fa-5a16-b48e-8959cc20329e', 'fa', 'وقت', 'من وقت کافی برای خواندن این کتاب ندارم.'),
  ('4a7f8aeb-c53b-541f-a97a-f4462262649b', '4fa7962f-0527-5231-86ae-e7adcb123b67', 'fa', 'به دست آوردن', 'من یک کتاب جدید به دست آوردم.'),
  ('9e2328ea-357d-5ab6-893b-3c5c4fb5da21', 'ae027ac8-9875-5e86-8cc4-26c7fdbeaaab', 'fa', 'شدن', 'هوا تاریک شد.'),
  ('60fc5082-4ee1-5ad5-a725-d5ab74a42886', 'c32492ee-6149-5386-b835-170f21cf9b22', 'fa', 'تازه، نو', 'این ماشین تازه خریده شده است.'),
  ('b8a5a23e-cd55-558b-be53-b91ec2117c0d', 'f0e7adef-1e3d-5a30-a67c-1d8793991e58', 'fa', 'بی‌سابقه، نوآورانه', 'او یک ایده نوآورانه برای این پروژه پیشنهاد کرد.'),
  ('e48382e3-b445-5312-adb4-99243d457d5e', 'f5d4984d-ee52-5c6b-9619-10646061da93', 'fa', 'گروهی از انسان‌ها', 'مردم زیادی در پارک حضور داشتند.'),
  ('19e1f422-f230-5278-afba-2cd3167708b7', '44e0be5d-6297-5149-b3b9-5bc82dc90a97', 'fa', 'شهروندان', 'دولت باید از منافع مردم کشور دفاع کند.'),
  ('3f61262a-9b1e-5bd1-ba76-5199f5d22e01', '06c88cd2-0352-5bdd-8a73-3d21fbab39bb', 'fa', 'همچنین', 'او یک معلم است و همچنین یک نویسنده است.'),
  ('a5c5e33d-0c68-5621-9971-64d5685455cc', '10ee5415-9b90-53fb-ba89-c7705cd184a1', 'fa', 'در این لحظه از روایت', 'او وارد اتاق می‌شود و اکنون می‌بیند که همه جا خالی است.'),
  ('a347d700-3d9f-5540-974a-9b7338616f76', '4984b9f7-8995-5c58-b230-96edcb592b97', 'fa', 'در این زمان‌ها، امروزه', 'الان مردم بیشتر وقتشان را با موبایل می‌گذرانند.'),
  ('0a781323-fd37-51c9-9bde-fa9d905098d6', '72e8deb3-54f4-57d9-a4c4-b6cdc02bc51d', 'fa', 'دیگر', 'من می‌خواهم کتاب دیگری بخوانم.'),
  ('b2997106-5f05-50b3-8968-0ff1f9af7dd4', 'de6c5229-f0b0-5533-a9b8-13a74b9292a8', 'fa', 'گذشته', 'روز دیگر او را دیدم.'),
  ('350ef549-65fe-5b71-b78d-170151b98dd3', 'b46d1050-7949-52ba-bb0a-0f8983b1a8f8', 'fa', 'خوب، مطلوب', 'این یک کتاب خوب است.'),
  ('29c134fb-7d5a-531e-8cc7-cf443b5973c3', '25c0af40-176b-5e29-84d7-400845f7ecdd', 'fa', 'کافی، مناسب', 'این مقدار برای ما خوب است.'),
  ('f2a4cb3a-b22e-5279-aca7-bd5f17e64a03', 'ac73a03b-2fd0-5427-9491-df8cc55c5b21', 'fa', 'تنها', 'او تنها فرزند خانواده است.'),
  ('e65d257d-4bb5-52f1-a8ed-b92f806c7678', 'c9b97ffe-fb8d-50b4-a47c-42aba6f2abdf', 'fa', 'منحصر به فرد', 'این کتاب منحصر به فرد است و دیگری مثل آن نیست.'),
  ('3c7362c6-7cc5-50e0-b44a-33a9d0684d6d', '03d07507-6043-5cd1-85a6-c4fb597c52d9', 'fa', 'فقط', 'من فقط آب می‌خورم، چیز دیگری نمی‌خورم.'),
