  ('69d11286-fb62-5ed5-b9e1-6c26ab05d155', '17ab4507-83d7-53ba-ba7d-723f0533374f', 'fa', 'وسیله، راه', 'تحصیل یک راه خوب برای موفقیت است.'),
  ('1596f55b-3885-5889-b712-d4bd0f95b3ea', '6c6ca7da-1948-5549-a4d3-c2272849f245', 'fa', 'بیشترین', 'او بیشترین امتیاز را در امتحان گرفت.'),
  ('326f6ff3-9466-5ef7-902a-f43b33d23f0d', '5ee91dcd-cad1-5190-a1dc-ba0f728dcadb', 'fa', 'بیشترین', 'این کتاب بیشترین فروش را در این ماه داشت.'),
  ('c5e2a9dd-51fb-5c71-af07-f8d6f2ea6f5b', '2e288a8b-b6ab-5235-91a7-9cfe1cd6e4f0', 'fa', 'بیشتر (برای تشکیل حالت برتر)', 'این فیلم از آن فیلم بیشتر جالب است.'),
  ('98f4062d-27a1-554f-92e4-e610464a9a6f', 'f3422d14-d528-5599-8a37-f0f5e08da0a1', 'fa', 'بسیار', 'این غذا بسیار خوشمزه است.'),
  ('703559a3-74db-59b3-8a46-b7cc9fbe34a7', '6d6af76c-2a82-5313-99fe-122cd17b6627', 'fa', 'خیلی زیاد', 'من خیلی زیاد آب می‌خورم.'),
  ('c4a1e15b-3d17-5faa-b4f3-2ebfb8fa46ae', 'ef7a20d1-4ec2-5a4e-996f-be2d6e6e47d1', 'fa', 'به میزان زیادی', 'این کتاب بسیار بهتر است.'),
  ('63d36c1e-8fad-52e4-ba30-fea190dc272d', '672be32a-d637-5098-ba9d-14780a963b4b', 'fa', 'بسیار', 'او خیلی خوب می‌خواند.'),
  ('d781049e-8669-50d3-a4c4-f3dea682f99f', '9f32e48d-fc13-50ce-88a3-c855f4a00729', 'fa', 'دقیقاً همانطور که گفته شده', 'این کتاب very مفید است.'),
  ('91ea2678-b4bd-540b-ba98-b646eb8b1659', '5ccefa2c-bb3e-59a4-a4a8-a4da7a4a8c4e', 'fa', 'همان یک چیز؛ نه چیز دیگری', 'در very لحظه‌ای که رفتم، او آمد.'),
  ('beb2c3eb-8f21-5cf9-ae73-b727f7b87738', 'de5d6631-ff6b-5f9c-97b1-27900ace5785', 'fa', 'خیلی؛ بسیار', 'هوا امروز very گرم است.'),
  ('5652c8b8-40a3-5232-bd30-b0f7e8b84e80', '373c49a8-7d93-5275-9e23-484998f05a6d', 'fa', 'دقیقاً؛ همین‌طور', 'very درست است که می‌گویی.'),
  ('68fff37e-3c95-5944-b0cb-8b59d8616b09', '83ae8a3b-705b-5f02-a10a-fb4f63e3c560', 'fa', 'حتی', 'حتی او هم نتوانست این مسئله را حل کند.'),
  ('de1b9f05-1a85-529e-915f-8f25ea85debc', 'd4dd4113-2a8d-516a-9e00-f50e39adcb8f', 'fa', 'حتی اگر، علی‌رغم', 'حتی اگر باران ببارد، ما همچنان می‌رویم.'),
  ('d0eecb22-d104-5ef5-acd4-642c2e7ac05e', '7b63d077-0a4e-58c4-b091-d1fefd9cb08a', 'fa', 'اینجا، این جا', 'من اینجا هستم.'),
  ('e587a84e-fd08-5f53-a316-53af20f65067', 'a41070f2-f0f4-5ed3-97fd-cce5a8a9f7d1', 'fa', 'در این مورد، در این باره', 'اینجا باید احتیاط کنیم.'),
  ('5bfee6b2-9eae-5f74-b4e1-8d8400bfba95', '6af452f5-7b40-5f62-a9a3-6a6f2b35fe87', 'fa', 'نیاز', 'او به کمک فوری نیاز دارد.'),
